@layer mergora.components {
  [data-focus-ring="true"]:focus-visible {
    outline: var(--mrg-component-focus-indicator-width) solid
      var(--mrg-component-focus-indicator-color);
    outline-offset: var(--mrg-component-focus-indicator-offset);
    box-shadow: 0 0 0 var(--mrg-component-focus-indicator-width)
      var(--mrg-semantic-color-background-canvas);
  }

  [data-focus-ring="true"][data-focus-ring-contrast="strong"]:focus-visible {
    box-shadow:
      0 0 0 var(--mrg-component-focus-indicator-width) var(--mrg-semantic-color-background-canvas),
      0 0 0 calc(var(--mrg-component-focus-indicator-width) * 2)
        var(--mrg-component-focus-indicator-color);
    outline-color: transparent;
    outline-offset: calc(var(--mrg-component-focus-indicator-width) * 2);
  }

  @media (forced-colors: active) {
    [data-focus-ring="true"]:focus-visible,
    [data-focus-ring="true"][data-focus-ring-contrast="strong"]:focus-visible {
      box-shadow: none;
      outline: 3px solid Highlight;
      outline-offset: 3px;
      forced-color-adjust: auto;
    }
  }
}

import { forwardRef, type ReactElement } from "react";

import { Slot, type SlotProps } from "../slot/index";
import "./focus-ring.css";

export interface FocusRingProps extends Omit<SlotProps, "data-slot"> {
  /** Adds an inner contrast layer for controls rendered on unpredictable surfaces. */
  readonly contrast?: "standard" | "strong";
}

export const FocusRing = forwardRef<HTMLElement, FocusRingProps>(function FocusRing(
  { children, contrast = "standard", ...slotProps },
  ref,
): ReactElement {
  return (
    <Slot {...slotProps} ref={ref} data-focus-ring="true" data-focus-ring-contrast={contrast}>
      {children}
    </Slot>
  );
});

FocusRing.displayName = "FocusRing";
